var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"살아남은 반군들은 꽁무니 빼고 있어, 누님.","JPN":"反乱軍の生き残りは逃げているよ、姉さん。","ENG":"The remaining rebel forces are retreating, Ma'am.","TWN":"報告姊，倖存的叛軍逃逸中，"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"일단 고용된 입장으로서 묻는데, 추격할 건가?","JPN":"雇われているから一応聞くが、追うつもりか？","ENG":"I’m asking this as a hired gun but, shall we give chase?","TWN":"基於受雇的立場，我還是必須禮貌性地問一下，要追嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"마음은 굴뚝 같지만……. 아니.","JPN":"そうしたい気持ちは山々だけど……やめとく。","ENG":"I want to with all my heart but... No.","TWN":"我是很想追……但不行！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"파레마는 아직 저들이 장악하고 있어. 함부로 따라 들어갔다간 험한 꼴 보게 돼.","JPN":"パレマはまだ彼らが掌握している。むやみについて行ったらひどい目に遭う。","ENG":"Parema is still under their control. If we give chase, things will get ugly fast.","TWN":"波雷馬還在他們的掌握之下，一時衝動追上去恐怕會有危險。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"하하. 지휘도 잘하더니 판단도 상식적이라 다행이군.","JPN":"はは。指揮が上手いと思ったら、判断も常識的でよかった。","ENG":"Ha ha. It’s nice to work for someone with common sense.","TWN":"哈哈，還好你不只有領導力，判斷力也不差！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"아까 바이크로 유인해 오는 솜씨가 대단하던데, 혹시 선수 출신이야?","JPN":"さっきバイクで誘導するところが上手かったが、もしかして選手出身か？","ENG":"Back there, your skill with the motorcycle was incredible. Did you use to be a professional?","TWN":"我看你剛才騎摩托車的樣子，好像很厲害，你是賽車選手嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"선수라니 과찬이네. 여기저기 다니느라 손에 익은 정도야.","JPN":"選手なんて言いすぎよ。よく乗ってたから慣れただけ。","ENG":"How nice of you to say that. But, no, I’ve just had some practice here and there.","TWN":"沒這麼誇張啦，還賽車選手咧，只是我常常騎車到處跑，所以比較熟練而已。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"아, 그거 혹시 작업 멘트였어?","JPN":"あ、もしかしてそれナンパだった？","ENG":"Ah, was that a pick-up line?","TWN":"喔！你這是在跟我搭訕嗎？"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"영업도 겸해야 하는 프리랜서의 아부성 멘트라고 생각해.","JPN":"営業も必要なフリーランサーのお世辞だと思えばいい。","ENG":"Rather take it as a compliment from a freelancer that has to make sales.","TWN":"應該說是以利益為出發點的搭訕。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"우리 업계에선 그로니아 보안국 인간들과는 같은 카페도 다니지 말라고 하거든.","JPN":"こちらの業界ではグロニア保安局のやつらとは同じカフェにも入るなって言ってるからな。","ENG":"You know, people in my line of work try to avoid even being in the same building as people from the Gronia National Security.","TWN":"否則在我們業界都說，連和格羅尼亞安全局的人一起喝咖啡都最好不要呢！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"}}}},{"id":"L13_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"역시 용병 분들이 냄새를 잘 맡아.","JPN":"やっぱり、傭兵は勘がいいね。","ENG":"Ha, then people in your line of work have good sense.","TWN":"傭兵果然很敏銳呢！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"심문할 상대가 있어서 먼저 실례할게. 추가 수당은 내 상관에게 요구하면 돼.","JPN":"尋問する相手がいるからお先に失礼するわ。追加手当は私の上官に請求して。","ENG":"Please excuse me, I have to interrogate someone. I’ll take my leave. You may ask my boss for the bonus pay.","TWN":"我還想找個人問話，就先走一步，額外的費用可以找我的長官申請。"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RIFLE_FOX_NULL_NULL","text":{"KOREA":"계산이 깔끔해서 좋군. 종종 애용해 달라고.","JPN":"潔くていい。また呼んでくれよ。","ENG":"Wow, a bonus even? Please. Feel free to request for us anytime.","TWN":"這樣算得清清楚楚，真好！希望以後還有合作機會！"},"stage":{"bg":"COUNTRYROAD_02","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_FOX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"크윽…… 허억…… 허억…….","JPN":"くうっ……はあ……はあ……","ENG":"Argh... *Huff… Huff...*","TWN":"咳……咳咳……呃……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"급소도 아닌 곳에 총알 몇 발 맞았다고 엄살 부리지 마, 쓰레기.","JPN":"急所でもないところに何発か当たったからって泣き言言うな、くず。","ENG":"Oh please, don’t be so dramatic. None of your vitals were hit, scum.","TWN":"我根本沒打中你的要害，少在那邊給我裝模作樣的，垃圾！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"크흐…… 흐…… 흐흐…….","JPN":"くふ……ふ……ふふ……","ENG":"Hrgh... Ha... Haah...","TWN":"咳咳……呃……呼呼……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"너, 보안국 소속이지. 그 썩은 눈빛을 보니 알겠군.","JPN":"お前、保安局のやつだな。その腐った目を見ればわかる。","ENG":"Clearly you’re a member of the National Security. I can tell by that disgusting look in your eye.","TWN":"看你那腐敗的眼神就知道，你是安全局的吧！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"우리 대장님은…… 사생활은 지저분해도 선은 지키는 분이었어.","JPN":"俺らの隊長は……汚いとこもあったが、一線は超えない方だった。","ENG":"My Captain... Sure his personal life might have been a bit messy, but he was a good man.","TWN":"我們隊長……雖然私生活不檢點，但他的心地很善良。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"그 자리를 어떤 놈이 차지할지는 몰라도…… 시민들은 곧 네 년을 저주하게 될 거다.","JPN":"その席に誰が着くかはわからないが……市民はじきにお前を呪うことになるだろう。","ENG":"I don’t know who’s going to take his place but... The people will hate you for this.","TWN":"雖然不知道是誰會坐那上個位置……但市民們一定會詛咒你這個臭女人！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"나한테서 정보를 캐낼 생각이었다면 포기하시지. 네놈들한테는……","JPN":"俺から情報を聞き出すつもりだったら諦めろ。お前らには……","ENG":"You think I’m going to tell you anything? You bastards...","TWN":"我勸你不要想從我身上問到什麼，對你們這些傢伙……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"여기는 원래 종교 시설이었어. 종파 따윈 모르지만.","JPN":"ここはもともと宗教施設だった。どの宗派かは知らないけど。","ENG":"You know, this place was originally a place of worship. Though I’m not sure of which religion it belonged to.","TWN":"這裡原本是宗教場所，不過我不清楚是哪個宗派的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"……갑자기 무슨 헛소리냐? 고문하기 전에 분위기라도 내려고?","JPN":"……いきなり何寝言を言ってるんだ？　拷問の前に雰囲気でも出すつもりか？","ENG":"...What are you saying all of a sudden? Trying to set the mood before you torture me?","TWN":"……你在胡說八道什麼？現在是逼供前先跟我閒話家常嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그냥 조사하면서 알게 된 이야기야.","JPN":"ただ調べる中で知った話よ。","ENG":"Oh, it’s just something I learned while I was investigating.","TWN":"這是我在調查時發現的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"교인들을 처형했다지? 집회를 허락해 준다는 구실로 모아 놓고 말이야.","JPN":"教徒を処刑したんだって？　集会の許可を口実に集めといてさ。","ENG":"Did you know that the believers were all executed? They were gathered together under the pretext of a normal assembly.","TWN":"信徒們全都遭到處決對吧？你們用允許集會的名義將他們聚集後，再將他們一併處決。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"……그래서, 그게 잘못이다? 애들에게 구시대적인 사고방식을 주입하던 놈들을 없앤 게?","JPN":"……それで、それが間違ってるとでも？　子どもたちに古い考え方を注入してたやつらを殺したのが？","ENG":"...And? What’s wrong with getting rid of people with such an outdated world view?","TWN":"……所以呢？這有什麼問題嗎？他們灌輸兒童老舊的思想，除掉他們何錯之有？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"흐흐……. 코메디가 따로없군. 네놈들은 세상 온갖 더러운 짓은 전부 저지르면서…….","JPN":"ふふ……笑えるぜ。お前らはあらゆる汚い真似をしておいて……","ENG":"Ha ha... What a joke. Acting the judge while you bastards have done countless terrible things...","TWN":"哈哈……真是可笑！你們明明壞事幹盡……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네가 처형 책임자였지?","JPN":"君が処刑の責任者だったね？","ENG":"You were in charge of that execution, weren’t you?","TWN":"是你負責行刑的吧？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"어떻게 알았는지 궁금해하지 마. 네 말대로 보안국은 더러운 짓이 일상이니까.","JPN":"どうしてわかったかなんて知らなくてもいい。君の言うとおり、保安局は汚い真似をするのが日常だから。","ENG":"You must be wondering how I know. Well, as you said, the Department of National Security is capable of doing “countless terrible things.”","TWN":"你不需要好奇我是怎麼知道的，因為就如同你所說的，安全局壞事幹盡。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"하나 정정해 줄게. 너에게서 캐낼 정보 따위는 처음부터 없었어.","JPN":"一つ言い直すわ。君から聞き出す情報なんて最初からなかった。","ENG":"I’ll let you in on a little secret. We never needed anything from you from the start.","TWN":"有件事我要更正一下，我打從一開始就沒想要從你身上問到什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"왜냐하면 네 마누라가 사흘 전에 자백제에 절은 채로 전부 불었거든.","JPN":"なぜなら君の女房が三日前自白剤を打たれて、全部吐いたからね。","ENG":"Three days ago, your wife in truth serum told us all we needed to know.","TWN":"因為你老婆三天前，在吐真劑的幫助下已經全盤托出。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"REVELA_NPC_NULL_SHIELD","text":{"KOREA":"자, 잠깐만! 나는 반년 넘게 저 도시에서 일했어! 원한다면 강경파 놈들 소식도……!","JPN":"ま、待ってくれ！　俺は半年以上あの街で働いたんだ！　欲しいなら強硬派の情報も……！","ENG":"W-wait! I worked in the city for over half a year! I-If you want I can give information on the hardliners...!","TWN":"先…先等一下！我已經在那個城市做事超過半年！強硬派的消息我也可以跟你……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REVELA_NPC_NULL_SHIELD","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"가서 마누라한테 안부나 전해 줘.","JPN":"君の女房によろしく。","ENG":"Give my regards to your wife.","TWN":"下去後代我向你老婆問好！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"나야, 레아. 안젤라. 잠깐 시간 괜찮아?","JPN":"レア、私よ。アンジェラ。ちょっといい？","ENG":"Yeah, it’s me. Angela. Do you have a moment?","TWN":"蕾亞，是我安潔拉，你方便說話嗎？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"응. 얘기해. 방금 막 일 하나가 끝났거든.","JPN":"うん、いいよ。さっき一仕事終わったところ。","ENG":"Sure. Go ahead. I just finished work.","TWN":"嗯，你說，我剛處理完一件事。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"많이 힘들어? 목소리가 많이 피곤한 것 같아.","JPN":"大丈夫？　声がだいぶ疲れてるみたい。","ENG":"Are you alright? You sound tired.","TWN":"很忙嗎？聽你的聲音很累的樣子。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"아니. 일하다가 사고 쳤어. 돌아가면 상사에게 혼나겠네.","JPN":"いや。仕事でドジっちゃったよ。帰ったら上司に怒られるね。","ENG":"It’s nothing. Just a slight mishap during work. Boss is going to be angry when I get back.","TWN":"不是，是處理的時候發生意外，回去應該會被長官罵得很慘。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그보다 무슨 일이야? 배급은 담당에게 넉넉히 주라고 얘기해 뒀는데.","JPN":"それより、どうしたの？　配給担当にはたくさんくれるようにって言っておいたけど。","ENG":"Is anything wrong? I ordered the distribution officer to give us excess rations.","TWN":"先不說這個，你找我什麼事？我已經跟負責配給的人交代好，要多給你一點。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아니. 루이제 아주머니…… 너희 어머니께서, 동네 아이를 데려가려다 시비가 붙었어.","JPN":"それじゃなくて。ルイーゼおばさん……あなたのお母さんが街の子どもを連れて行こうとして揉め事になったの。","ENG":"Madam Louise... Your mother, well there was a bit of an issue. She got in a fight while she was trying to pick up a kid in the neighborhood.","TWN":"不是的，是露易絲伯母……你媽媽她想要把一個小孩帶走，結果和人發生爭執。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"이런 위험한 곳에 있으면 안 된다고 하시면서. 너인 줄 아셨나 봐.","JPN":"こんな危ないところにいてはだめとか言ってたわ。あなたと勘違いしたみたい。","ENG":"She thought the place was too dangerous for a kid to be... She must have thought it was you.","TWN":"她可能誤以為那個小孩是你，就說不可以待在這麼危險的地方，想把人帶走。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……치매가 더 심해진 거지?","JPN":"……認知症がひどくなってるよね？","ENG":"Her dementia has worsened, hasn’t it?","TWN":"……她失智的情況又更嚴重了吧？"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아마도. 요즘 들어 더 자주 그러시는 것 같아.","JPN":"多分ね。最近頻度も増えてるし。","ENG":"It’s possible. These types of incidents seem to be occurring more often.","TWN":"好像是，最近她常常那樣。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"BASS_HARMONY_NULL_HIDE","text":{"KOREA":"아이 부모님께 사과드리기는 했는데, 너도 미리 알아 둬야 할 것 같아서.","JPN":"子どもの両親には謝っておいたけど、伝えなきゃいけないと思って。","ENG":"I already apologized to the child’s parents, but I still thought you should know.","TWN":"我有先跟小孩的父母道歉，但想說也先跟你說一聲。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 고마워, 안젤라.","JPN":"そう。ありがとう、アンジェラ。","ENG":"I see. Thank you. Angela.","TWN":"好，謝啦，安潔拉～"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"뒤처리 끝나는 대로……. 나도 따로 만나서 얘기해 볼게.","JPN":"後片付けが終わったらすぐ……会いに行って私も話してみる。","ENG":"Once this is all over...I’ll apologize to them as well.","TWN":"等我事情處理完……再親自去拜訪一趟。"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"멀어서 잘 보이진 않았지만……. 그 아이가 저격수였겠지.","JPN":"遠くて見えなかったけど……スナイパーはあの子だったはず。","ENG":"It was a bit far so I couldn’t see well, but... That kid looked like the sniper.","TWN":"雖然距離太遠看得不是很清楚……但狙擊手應該就是她吧？"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……그런 꼬마에게 당할 뻔했으니, 공작원으로는 실격이네.","JPN":"……あんなガキにやられそうになるとは、工作員としては失格ね。","ENG":"...I almost got taken out by a kid, what an operative I am.","TWN":"……竟然差點栽在那黃毛丫頭的手上，我真是個不及格的特務呢！"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MONTAGNE_ADMIN_NULL_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"나중에 만나면…… 인사라도 해야 하나.","JPN":"あとで会ったら……挨拶でもしないとかな。","ENG":"If I meet her later... should I say thank you to her?","TWN":"下次見面時……要和她打個招呼嗎？"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"subtitle","speaker":null,"text":{"KOREA":"그로니아 보안국 1급 공작원 레아 슈나이더: 코드명 <color=#ffd34c>레버넌트</color>\\n이력 말소 후 대기 처분.","JPN":"グロニア保安局1級工作員レア・シュナイダー コードネーム：<color=#ffd34c>レヴナント</color>\\n履歴抹消後待機処分。","ENG":"Gronia Department of National Security’s First-Class Operative Leah Schneider Codename: <color=#ffd34c>Revenant</color>\\nCareer placed on hold.","TWN":"格羅尼亞安全局1級特務 蕾亞·修奈德: 代號 <color=#ffd34c>亡靈</color>\\n履歷銷毀後停職處分"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"subtitle","speaker":null,"text":{"KOREA":"사유: 임무 중 과실","JPN":"理由：任務中過失","ENG":"Reason: Negligence during the mission","TWN":"事由: 任務中過失"},"stage":{"bg":"HARMONY_06","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};